import React, { useState } from 'react';

export function StarDisplay({ rating, size = 20 }) {
  return (
    <span className="star-display" style={{ fontSize: size }}>
      {[1, 2, 3, 4, 5].map(i => {
        if (rating >= i) return <span key={i} className="star full">★</span>;
        if (rating >= i - 0.5) return <span key={i} className="star half">★</span>;
        return <span key={i} className="star empty">★</span>;
      })}
    </span>
  );
}

export function StarPicker({ value, onChange }) {
  const [hover, setHover] = useState(null);
  const display = hover ?? value;

  return (
    <div className="star-picker" onMouseLeave={() => setHover(null)}>
      {[1, 2, 3, 4, 5].map(i => (
        <span key={i} className="star-pick-wrap">
          <span className="star-half-zone left" onMouseEnter={() => setHover(i - 0.5)} onClick={() => onChange(i - 0.5)} />
          <span className="star-half-zone right" onMouseEnter={() => setHover(i)} onClick={() => onChange(i)} />
          <span className={`star pick-star ${display >= i ? 'full' : display >= i - 0.5 ? 'half' : 'empty'}`}>★</span>
        </span>
      ))}
      {value ? <span className="star-value-label">{value} star{value !== 1 ? 's' : ''}</span> : <span className="star-value-label muted">Tap to rate</span>}
    </div>
  );
}
