import React, { useState, useEffect } from 'react';
import { fetchAuthSession, signInWithRedirect, signOut, getCurrentUser } from 'aws-amplify/auth';
import { Hub } from 'aws-amplify/utils';
import axios from 'axios';
import { API_BASE } from './aws-config';
import AdminView from './AdminView';
import UserView from './UserView';
import './App.css';

const VAPID_PUBLIC = 'BF81vtZSyIEWsVtrwDmT54446M7EwT6uCGpk37asxAlJn_j3uXY56a4EPq9hBr1h_5D2p5kUbvgsPOREL1c6lp0';

function urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const raw = window.atob(base64);
  return Uint8Array.from([...raw].map(c => c.charCodeAt(0)));
}

async function subscribePush(token) {
  if (!('serviceWorker' in navigator)) return 'Service workers not supported';
  if (!('PushManager' in window)) return 'Push not supported';
  if (!('Notification' in window)) return 'Notifications not supported';
  try {
    const reg = await Promise.race([
      navigator.serviceWorker.ready,
      new Promise((_, reject) => setTimeout(() => reject(new Error('SW timeout')), 8000)),
    ]);
    const permission = await Notification.requestPermission();
    if (permission !== 'granted') return `Permission ${permission}`;
    const sub = await reg.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC),
    });
    await axios.post(`${API_BASE}/push-subscriptions`, { subscription: sub.toJSON() }, {
      headers: { Authorization: token },
    });
    return 'granted';
  } catch (e) {
    return `Error: ${e.message}`;
  }
}

export default function App() {
  const [user, setUser] = useState(null);
  const [role, setRole] = useState(null);
  const [loading, setLoading] = useState(true);
  const [notifStatus, setNotifStatus] = useState(() => {
    if (!('Notification' in window)) return 'unsupported';
    return Notification.permission;
  });

  async function loadUser() {
    try {
      const cognitoUser = await getCurrentUser();
      const session = await fetchAuthSession();
      const token = session.tokens?.idToken?.toString();
      const payload = session.tokens?.idToken?.payload;
      const email = payload?.email;
      const res = await axios.post(`${API_BASE}/users`, {}, { headers: { Authorization: token } });
      setUser({ ...cognitoUser, email, token });
      setRole(res.data.role);
    } catch {
      setUser(null);
      setRole(null);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.register('/summer-sips/sw.js').catch(console.warn);
    }
    loadUser();
    const unsubscribe = Hub.listen('auth', ({ payload }) => {
      if (payload.event === 'signedIn') loadUser();
      if (payload.event === 'signedOut') { setUser(null); setRole(null); }
    });
    return unsubscribe;
  }, []);

  if (loading) return <div className="loading"><div className="spinner" />Loading...</div>;

  if (!user) {
    return (
      <div className="login-page">
        <div className="login-card">
          <div className="logo">🍹</div>
          <h1>Summer Sips</h1>
          <p>Order your favorite drinks</p>
          <button className="google-btn" onClick={() => signInWithRedirect({ provider: 'Google' })}>
            <svg viewBox="0 0 24 24" width="20" height="20"><path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/><path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>
            Sign in with Google
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-left">
          <span className="header-logo">🍹</span>
          <span className="header-title">Summer Sips</span>
        </div>
        <div className="header-right">
          <span className="header-email">{user.email}</span>
          {role === 'admin' && <span className="admin-badge">Admin</span>}
          {role === 'admin' && notifStatus !== 'unsupported' && (
            <button className="notif-btn" title={notifStatus} onClick={async () => {
              setNotifStatus('subscribing');
              const result = await subscribePush(user.token);
              const current = ('Notification' in window) ? Notification.permission : 'unsupported';
              setNotifStatus(result === 'granted' ? 'granted' : (current === 'granted' ? 'granted' : result || current));
            }}>
              {notifStatus === 'subscribing' ? '⏳ Enabling…'
                : notifStatus === 'granted' ? '🔔 On · Re-enable'
                : notifStatus === 'denied' ? '🔕 Blocked — tap to retry'
                : '🔔 Enable Notifications'}
            </button>
          )}
          <button className="signout-btn" onClick={() => signOut()}>Sign out</button>
        </div>
      </header>
      <main>
        {role === 'admin'
          ? <AdminView token={user.token} />
          : <UserView token={user.token} userEmail={user.email} />}
      </main>
    </div>
  );
}
