import React, { useState } from 'react';

export default function IngredientPicker({ available, selected, onChange }) {
  const [search, setSearch] = useState('');

  const unselected = available.filter(
    a => !selected.find(s => s.id === a.id) && a.name.toLowerCase().includes(search.toLowerCase())
  );

  function addIngredient(ing) {
    if (ing.type === 'boolean') {
      onChange([...selected, { id: ing.id, name: ing.name, type: ing.type, amount: 100 }]);
    } else {
      onChange([...selected, { id: ing.id, name: ing.name, type: ing.type, quantity: 1 }]);
    }
  }

  function removeIngredient(id) {
    onChange(selected.filter(s => s.id !== id));
  }

  function updateQuantity(id, delta) {
    onChange(selected.map(s => s.id === id ? { ...s, quantity: Math.max(0.5, +(s.quantity + delta).toFixed(1)) } : s));
  }

  function updateAmount(id, delta) {
    onChange(selected.map(s => s.id === id ? { ...s, amount: Math.min(800, Math.max(100, (s.amount || 100) + delta)) } : s));
  }

  return (
    <div className="ingredient-picker">
      <div className="selected-ingredients">
        {selected.length === 0 && <div className="picker-empty">No ingredients added yet</div>}
        {selected.map(s => (
          <div key={s.id} className="selected-ing">
            <span className="ing-name">{s.name}</span>
            {s.type === 'boolean' ? (
              <div className="qty-controls">
                <button onClick={() => updateAmount(s.id, -100)}>−</button>
                <span>{s.amount || 100}</span>
                <button onClick={() => updateAmount(s.id, 100)}>+</button>
              </div>
            ) : (
              <div className="qty-controls">
                <button onClick={() => updateQuantity(s.id, -0.5)}>−</button>
                <span>{s.quantity}</span>
                <button onClick={() => updateQuantity(s.id, 0.5)}>+</button>
              </div>
            )}
            <button className="remove-ing" onClick={() => removeIngredient(s.id)}>✕</button>
          </div>
        ))}
      </div>
      <input
        className="picker-search"
        placeholder="Search ingredients..."
        value={search}
        onChange={e => setSearch(e.target.value)}
      />
      <div className="picker-chips">
        {unselected.map(ing => (
          <button key={ing.id} className="picker-chip" onClick={() => addIngredient(ing)}>
            + {ing.name}
            {ing.type === 'squirt' && <span className="squirt-label">squirt</span>}
          </button>
        ))}
      </div>
    </div>
  );
}
