import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { API_BASE } from './aws-config';
import IngredientPicker from './IngredientPicker';
import { StarDisplay } from './StarRating';

const STATUS_FLOW = ['pending', 'making', 'ready', 'delivered'];
const STATUS_LABELS = { pending: 'Pending', making: 'Making', ready: 'Ready', delivered: 'Delivered' };

export default function AdminView({ token }) {
  const [tab, setTab] = useState('orders');
  const [orders, setOrders] = useState([]);
  const [drinks, setDrinks] = useState([]);
  const [suggestions, setSuggestions] = useState([]);
  const [ingredients, setIngredients] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newDrink, setNewDrink] = useState({ name: '', description: '', ingredients: [] });
  const [editDrink, setEditDrink] = useState(null);
  const [expandedDrink, setExpandedDrink] = useState(null);
  const [saving, setSaving] = useState(false);
  const [newIngredient, setNewIngredient] = useState({ name: '', type: 'quantity', quantity: 0, inStock: true });
  const [openChat, setOpenChat] = useState(null);
  const [chatInput, setChatInput] = useState({});
  const [sendingMsg, setSendingMsg] = useState(false);

  const h = { Authorization: token };

  const loadOrders = useCallback(async () => {
    const res = await axios.get(`${API_BASE}/orders`, { headers: h });
    setOrders(res.data);
  }, [token]);

  const loadAll = useCallback(async () => {
    const [drinksRes, suggestionsRes, ingredientsRes, reviewsRes] = await Promise.all([
      axios.get(`${API_BASE}/drinks`, { headers: h }),
      axios.get(`${API_BASE}/suggestions`, { headers: h }),
      axios.get(`${API_BASE}/ingredients`, { headers: h }),
      axios.get(`${API_BASE}/reviews`, { headers: h }),
    ]);
    setDrinks(drinksRes.data);
    setSuggestions(suggestionsRes.data);
    setIngredients(ingredientsRes.data);
    setReviews(reviewsRes.data);
  }, [token]);

  useEffect(() => {
    Promise.all([loadOrders(), loadAll()]).finally(() => setLoading(false));
    const interval = setInterval(loadOrders, openChat ? 3000 : 15000);
    return () => clearInterval(interval);
  }, [loadOrders, loadAll, openChat]);

  async function advanceOrder(order) {
    const next = STATUS_FLOW[STATUS_FLOW.indexOf(order.status) + 1];
    if (!next) return;
    await axios.put(`${API_BASE}/orders/${order.id}`, { status: next }, { headers: h });
    setOrders(prev => prev.map(o => o.id === order.id ? { ...o, status: next } : o));
  }

  async function sendMessage(order) {
    const text = chatInput[order.id]?.trim();
    if (!text) return;
    setSendingMsg(true);
    try {
      const res = await axios.post(`${API_BASE}/orders/${order.id}/message`, { text }, { headers: h });
      setOrders(prev => prev.map(o => o.id === order.id
        ? { ...o, messages: [...(o.messages || []), res.data] } : o));
      setChatInput(prev => ({ ...prev, [order.id]: '' }));
    } catch(e) {} finally { setSendingMsg(false); }
  }

  async function saveDrink() {
    setSaving(true);
    try {
      const res = await axios.post(`${API_BASE}/drinks`, newDrink, { headers: h });
      setDrinks(prev => [...prev, res.data]);
      setNewDrink({ name: '', description: '', ingredients: [] });
    } catch(e) {} finally { setSaving(false); }
  }

  async function updateDrink() {
    setSaving(true);
    try {
      await axios.put(`${API_BASE}/drinks/${editDrink.id}`, editDrink, { headers: h });
      setDrinks(prev => prev.map(d => d.id === editDrink.id ? editDrink : d));
      setEditDrink(null);
    } catch(e) {} finally { setSaving(false); }
  }

  async function deleteDrink(id) {
    await axios.delete(`${API_BASE}/drinks/${id}`, { headers: h });
    setDrinks(prev => prev.filter(d => d.id !== id));
  }

  async function toggleAvailable(drink) {
    const updated = { ...drink, available: !drink.available };
    await axios.put(`${API_BASE}/drinks/${drink.id}`, updated, { headers: h });
    setDrinks(prev => prev.map(d => d.id === drink.id ? updated : d));
  }

  async function handleSuggestion(id, action) {
    const res = await axios.put(`${API_BASE}/suggestions/${id}`, { action }, { headers: h });
    setSuggestions(prev => prev.filter(s => s.id !== id));
    if (action === 'accept') {
      const suggestion = suggestions.find(s => s.id === id);
      if (suggestion?.suggestionType === 'ingredient') {
        setIngredients(prev => [...prev, res.data]);
      } else {
        setDrinks(prev => [...prev, res.data]);
      }
    }
  }

  async function addIngredient() {
    const res = await axios.post(`${API_BASE}/ingredients`, newIngredient, { headers: h });
    setIngredients(prev => [...prev, res.data]);
    setNewIngredient({ name: '', type: 'quantity', quantity: 0, inStock: true });
  }

  async function updateIngredientQty(ing, delta) {
    const updated = { ...ing, quantity: Math.max(0.5, +(ing.quantity + delta).toFixed(1)) };
    await axios.put(`${API_BASE}/ingredients/${ing.id}`, updated, { headers: h });
    setIngredients(prev => prev.map(i => i.id === ing.id ? updated : i));
  }

  async function toggleIngStock(ing) {
    const updated = { ...ing, inStock: !ing.inStock };
    await axios.put(`${API_BASE}/ingredients/${ing.id}`, updated, { headers: h });
    setIngredients(prev => prev.map(i => i.id === ing.id ? updated : i));
  }

  async function deleteIngredient(id) {
    await axios.delete(`${API_BASE}/ingredients/${id}`, { headers: h });
    setIngredients(prev => prev.filter(i => i.id !== id));
  }

  const activeOrders = orders.filter(o => o.status !== 'delivered');
  const pastOrders = orders.filter(o => o.status === 'delivered');
  const drinkSuggestions = suggestions.filter(s => !s.suggestionType || s.suggestionType === 'drink');
  const ingredientSuggestions = suggestions.filter(s => s.suggestionType === 'ingredient');

  if (loading) return <div className="loading"><div className="spinner" />Loading...</div>;

  return (
    <div className="admin-view">
      <div className="tab-bar">
        <button className={tab === 'orders' ? 'tab active' : 'tab'} onClick={() => setTab('orders')}>
          Orders {activeOrders.length > 0 && <span className="badge">{activeOrders.length}</span>}
        </button>
        <button className={tab === 'drinks' ? 'tab active' : 'tab'} onClick={() => setTab('drinks')}>Drinks</button>
        <button className={tab === 'suggestions' ? 'tab active' : 'tab'} onClick={() => setTab('suggestions')}>
          Suggestions {suggestions.length > 0 && <span className="badge">{suggestions.length}</span>}
        </button>
        <button className={tab === 'inventory' ? 'tab active' : 'tab'} onClick={() => setTab('inventory')}>Inventory</button>
        <button className={tab === 'history' ? 'tab active' : 'tab'} onClick={() => setTab('history')}>History</button>
        <button className={tab === 'reviews' ? 'tab active' : 'tab'} onClick={() => setTab('reviews')}>Reviews</button>
      </div>

      {tab === 'orders' && (
        <div className="orders-list">
          {activeOrders.length === 0
            ? <div className="empty">No active orders</div>
            : activeOrders.map(order => (
              <div key={order.id} className={`order-card status-${order.status}`}>
                <div className="order-top">
                  <span className="order-drink">{order.drinkName}</span>
                  <span className={`status-pill ${order.status}`}>{STATUS_LABELS[order.status]}</span>
                </div>
                <div className="order-meta">
                  <span className="order-user">{order.userName}</span>
                  <span className="order-time">{new Date(order.createdAt + 'Z').toLocaleTimeString()}</span>
                </div>
                <div className="order-extras">
                  <span className="order-extra">{order.glass === 'green' ? '🍵 Green glass' : '🥃 Clear glass'}</span>
                  <span className="order-extra">{order.ice > 0 ? `🧊 Ice: ${order.ice}` : '🚫 No ice'}</span>
                </div>
                {order.modifications && order.modifications.length > 0 && (
                  <div className="order-mods">
                    {order.modifications.map(m => (
                      <span key={m.id} className={`order-mod ${m.action}`}>
                        {m.action === 'remove' ? `✕ ${m.name}` : m.action === 'add' ? `+ ${m.name}` : `~ ${m.name}${m.type !== 'boolean' ? ` ×${m.quantity}` : ''}`}
                      </span>
                    ))}
                  </div>
                )}
                {order.notes && <div className="order-notes">"{order.notes}"</div>}
                <div className="order-status-top" style={{ marginTop: 10 }}>
                  {order.status !== 'delivered' && (
                    <button className="advance-btn" onClick={() => advanceOrder(order)}>
                      → Mark as {STATUS_LABELS[STATUS_FLOW[STATUS_FLOW.indexOf(order.status) + 1]] || ''}
                    </button>
                  )}
                  {(order.status === 'making' || order.status === 'ready') && (
                    <button className="chat-toggle" onClick={() => setOpenChat(openChat === order.id ? null : order.id)}>
                      💬{(order.messages||[]).length > 0 ? ` ${order.messages.length}` : ''}
                    </button>
                  )}
                </div>
                {(order.status === 'making' || order.status === 'ready') && openChat === order.id && (
                  <div className="chat-panel">
                    <div className="chat-messages">
                      {(order.messages || []).length === 0
                        ? <div className="chat-empty">No messages yet</div>
                        : (order.messages || []).map(m => (
                          <div key={m.id} className={`chat-bubble ${m.isAdmin ? 'admin' : 'user'}`}>
                            <div className="chat-text">{m.text}</div>
                            <div className="chat-meta">{m.senderName}</div>
                          </div>
                        ))
                      }
                    </div>
                    <div className="chat-input-row">
                      <input className="chat-input" placeholder="Reply..."
                        value={chatInput[order.id] || ''}
                        onChange={e => setChatInput(p => ({ ...p, [order.id]: e.target.value }))}
                        onKeyDown={e => e.key === 'Enter' && sendMessage(order)} />
                      <button className="chat-send-btn" onClick={() => sendMessage(order)} disabled={sendingMsg}>Send</button>
                    </div>
                  </div>
                )}
              </div>
            ))
          }
        </div>
      )}

      {tab === 'drinks' && (
        <div className="drinks-admin">
          <div className="add-drink-form">
            <h2>{editDrink ? 'Edit Drink' : 'Add New Drink'}</h2>
            {editDrink ? (
              <>
                <input value={editDrink.name} onChange={e => setEditDrink(p => ({ ...p, name: e.target.value }))} placeholder="Drink name" />
                <textarea value={editDrink.description} onChange={e => setEditDrink(p => ({ ...p, description: e.target.value }))} placeholder="Description" rows={2} />
                <IngredientPicker available={ingredients} selected={editDrink.ingredients || []}
                  onChange={ings => setEditDrink(p => ({ ...p, ingredients: ings }))} />
                <div className="edit-actions">
                  <button onClick={updateDrink} disabled={saving}>{saving ? 'Saving...' : 'Save'}</button>
                  <button onClick={() => setEditDrink(null)}>Cancel</button>
                </div>
              </>
            ) : (
              <>
                <input value={newDrink.name} onChange={e => setNewDrink(p => ({ ...p, name: e.target.value }))} placeholder="Drink name" />
                <textarea value={newDrink.description} onChange={e => setNewDrink(p => ({ ...p, description: e.target.value }))} placeholder="Description" rows={2} />
                <IngredientPicker available={ingredients} selected={newDrink.ingredients}
                  onChange={ings => setNewDrink(p => ({ ...p, ingredients: ings }))} />
                <button onClick={saveDrink} disabled={!newDrink.name.trim() || saving}>{saving ? 'Saving...' : 'Add Drink'}</button>
              </>
            )}
          </div>
          <div className="drinks-list">
            {drinks.map(drink => (
              <div key={drink.id} className={`drink-card ${drink.available ? '' : 'unavailable'}`}>
                <div style={{ flex: 1 }}>
                  <div className="drink-name">
                    {drink.name}
                    {!drink.available && <span className="unavailable-tag">Hidden</span>}
                  </div>
                  {drink.description && <div className="drink-desc">{drink.description}</div>}
                  {expandedDrink === drink.id && (drink.ingredients || []).length > 0 && (
                    <div className="recipe-section">
                      <div className="recipe-title">Ingredients</div>
                      <ul className="recipe-list">
                        {(drink.ingredients || []).map(ing => (
                          <li key={ing.id}>{ing.name}{ing.type === 'boolean'
                            ? ing.amount && <span className="recipe-qty"> {ing.amount}</span>
                            : <span className="recipe-qty"> ×{ing.quantity}</span>}</li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
                <div className="drink-actions">
                  <button onClick={() => setExpandedDrink(expandedDrink === drink.id ? null : drink.id)}>
                    {expandedDrink === drink.id ? 'Hide' : 'Recipe'}
                  </button>
                  <button onClick={() => setEditDrink(drink)}>Edit</button>
                  <button onClick={() => toggleAvailable(drink)}>{drink.available ? 'Hide' : 'Show'}</button>
                  <button className="delete-btn" onClick={() => deleteDrink(drink.id)}>Delete</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {tab === 'suggestions' && (
        <div>
          {suggestions.length === 0
            ? <div className="empty">No suggestions yet</div>
            : <>
                {drinkSuggestions.length > 0 && (
                  <div className="suggestions-group">
                    <h3 className="suggestions-group-title">Drink Suggestions</h3>
                    <div className="suggestions-list">
                      {drinkSuggestions.map(s => (
                        <div key={s.id} className="suggestion-card">
                          <div className="suggestion-top">
                            <span className="suggestion-name">{s.name}</span>
                            <span className="suggestion-user">{s.userName}</span>
                          </div>
                          {s.description && <div className="suggestion-desc">{s.description}</div>}
                          {s.ingredients && s.ingredients.length > 0 && (
                            <div className="suggestion-ings">{s.ingredients.map(i => i.name).join(', ')}</div>
                          )}
                          <div className="suggestion-actions">
                            <button className="accept-btn" onClick={() => handleSuggestion(s.id, 'accept')}>Add to Menu</button>
                            <button className="decline-btn" onClick={() => handleSuggestion(s.id, 'decline')}>Decline</button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                {ingredientSuggestions.length > 0 && (
                  <div className="suggestions-group">
                    <h3 className="suggestions-group-title">Ingredient Suggestions</h3>
                    <div className="suggestions-list">
                      {ingredientSuggestions.map(s => (
                        <div key={s.id} className="suggestion-card">
                          <div className="suggestion-top">
                            <span className="suggestion-name">{s.name}</span>
                            <span className="suggestion-user">{s.userName}</span>
                          </div>
                          <div className="suggestion-desc">
                            Type: <strong>{s.ingredientType === 'boolean' ? 'In/Out of Stock' : s.ingredientType === 'squirt' ? 'Squirt' : 'Quantity'}</strong>
                          </div>
                          <div className="suggestion-actions">
                            <button className="accept-btn" onClick={() => handleSuggestion(s.id, 'accept')}>Add to Inventory</button>
                            <button className="decline-btn" onClick={() => handleSuggestion(s.id, 'decline')}>Decline</button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </>
          }
        </div>
      )}

      {tab === 'inventory' && (
        <div className="inventory-section">
          <div className="add-ingredient-form">
            <h2>Add Ingredient</h2>
            <input placeholder="Name" value={newIngredient.name} onChange={e => setNewIngredient(p => ({ ...p, name: e.target.value }))} />
            <div className="type-select">
              {['quantity', 'boolean', 'squirt'].map(t => (
                <button key={t} className={newIngredient.type === t ? 'opt-btn active' : 'opt-btn'}
                  onClick={() => setNewIngredient(p => ({ ...p, type: t }))}>
                  {t === 'boolean' ? 'In/Out of Stock' : t === 'squirt' ? 'Squirt' : 'Quantity'}
                </button>
              ))}
            </div>
            {newIngredient.type === 'quantity' && (
              <div className="qty-controls">
                <button onClick={() => setNewIngredient(p => ({ ...p, quantity: Math.max(0, +(p.quantity - 0.5).toFixed(1)) }))}>−</button>
                <span>{newIngredient.quantity}</span>
                <button onClick={() => setNewIngredient(p => ({ ...p, quantity: +(p.quantity + 0.5).toFixed(1) }))}>+</button>
              </div>
            )}
            <button onClick={addIngredient} disabled={!newIngredient.name.trim()}>Add</button>
          </div>
          <div className="ingredients-list">
            {ingredients.map(ing => (
              <div key={ing.id} className="ingredient-row">
                <span className="ing-name">
                  {ing.name}
                  {ing.type === 'squirt' && <span className="squirt-label">squirt</span>}
                </span>
                {ing.type === 'quantity'
                  ? <div className="qty-controls">
                      <button onClick={() => updateIngredientQty(ing, -0.5)}>−</button>
                      <span>{ing.quantity}</span>
                      <button onClick={() => updateIngredientQty(ing, 0.5)}>+</button>
                    </div>
                  : <button className={`stock-btn ${ing.inStock !== false ? 'in' : 'out'}`} onClick={() => toggleIngStock(ing)}>
                      {ing.inStock !== false ? 'In Stock' : 'Out of Stock'}
                    </button>
                }
                <button className="delete-btn" onClick={() => deleteIngredient(ing.id)}>✕</button>
              </div>
            ))}
          </div>
        </div>
      )}

      {tab === 'history' && (
        <div className="orders-list">
          {pastOrders.length === 0
            ? <div className="empty">No delivered orders yet</div>
            : pastOrders.map(order => (
              <div key={order.id} className="order-card status-delivered">
                <div className="order-top">
                  <span className="order-drink">{order.drinkName}</span>
                  <span className="status-pill delivered">Delivered</span>
                </div>
                <div className="order-meta">
                  <span className="order-user">{order.userName}</span>
                  <span className="order-time">{new Date(order.createdAt + 'Z').toLocaleString()}</span>
                </div>
                <div className="order-extras">
                  <span className="order-extra">{order.glass === 'green' ? '🍵 Green glass' : '🥃 Clear glass'}</span>
                  <span className="order-extra">{order.ice > 0 ? `🧊 Ice: ${order.ice}` : '🚫 No ice'}</span>
                </div>
                {order.modifications && order.modifications.length > 0 && (
                  <div className="order-mods">
                    {order.modifications.map(m => (
                      <span key={m.id} className={`order-mod ${m.action}`}>
                        {m.action === 'remove' ? `✕ ${m.name}` : m.action === 'add' ? `+ ${m.name}` : `~ ${m.name}${m.type !== 'boolean' ? ` ×${m.quantity}` : ''}`}
                      </span>
                    ))}
                  </div>
                )}
                {order.notes && <div className="order-notes">"{order.notes}"</div>}
              </div>
            ))
          }
        </div>
      )}

      {tab === 'reviews' && (() => {
        const ratings = [0.5,1,1.5,2,2.5,3,3.5,4,4.5,5];
        const counts = Object.fromEntries(ratings.map(r => [r, 0]));
        reviews.forEach(r => { if (counts[r.rating] !== undefined) counts[r.rating]++; });
        const avg = reviews.length ? (reviews.reduce((s, r) => s + r.rating, 0) / reviews.length) : 0;
        const maxCount = Math.max(...Object.values(counts), 1);
        return (
          <div className="reviews-tab">
            {reviews.length === 0
              ? <div className="empty">No reviews yet</div>
              : <>
                  <div className="reviews-summary">
                    <div className="reviews-avg">
                      <span className="avg-number">{avg.toFixed(1)}</span>
                      <StarDisplay rating={avg} size={24} />
                      <span className="reviews-count">{reviews.length} review{reviews.length !== 1 ? 's' : ''}</span>
                    </div>
                    <div className="rating-chart">
                      {ratings.map(r => (
                        <div key={r} className="chart-row">
                          <span className="chart-label">{r}</span>
                          <div className="chart-bar-bg">
                            <div className="chart-bar-fill" style={{ width: `${(counts[r] / maxCount) * 100}%` }} />
                          </div>
                          <span className="chart-count">{counts[r]}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="reviews-list">
                    {reviews.map(r => (
                      <div key={r.id} className="review-card">
                        <div className="review-top">
                          <StarDisplay rating={r.rating} />
                          <span className="review-user">{r.userName}</span>
                          <span className="review-date">{new Date(r.createdAt + 'Z').toLocaleDateString()}</span>
                        </div>
                        {r.message && <p className="review-msg">{r.message}</p>}
                      </div>
                    ))}
                  </div>
                </>
            }
          </div>
        );
      })()}
    </div>
  );
}
