import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { API_BASE } from './aws-config';
import IngredientPicker from './IngredientPicker';
import { StarDisplay, StarPicker } from './StarRating';

const STATUS_LABELS = { pending: 'Order received', making: 'Being made', ready: 'Ready for pickup!', delivered: 'Delivered' };
const STATUS_ICONS = { pending: '⏳', making: '👨‍🍳', ready: '🎉', delivered: '✅' };

export default function UserView({ token, userEmail }) {
  const [tab, setTab] = useState('main');
  const [drinks, setDrinks] = useState([]);
  const [orders, setOrders] = useState([]);
  const [ingredients, setIngredients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [ordering, setOrdering] = useState(null);
  const [notes, setNotes] = useState('');
  const [ice, setIce] = useState(0);
  const [glass, setGlass] = useState('clear');
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(null);
  const [expandedDrink, setExpandedDrink] = useState(null);
  const [modifications, setModifications] = useState({});
  const [expandedMod, setExpandedMod] = useState(null);
  const [showSuggestForm, setShowSuggestForm] = useState(false);
  const [suggestion, setSuggestion] = useState({ name: '', description: '', ingredients: [] });
  const [suggesting, setSuggesting] = useState(false);
  const [suggestSuccess, setSuggestSuccess] = useState(false);
  const [openChat, setOpenChat] = useState(null);
  const [chatInput, setChatInput] = useState({});
  const [sendingMsg, setSendingMsg] = useState(false);
  const [reviews, setReviews] = useState([]);
  const [reviewRating, setReviewRating] = useState(null);
  const [reviewMessage, setReviewMessage] = useState('');
  const [submittingReview, setSubmittingReview] = useState(false);
  const [reviewSuccess, setReviewSuccess] = useState(false);
  // Ingredient suggestion
  const [showIngSuggestForm, setShowIngSuggestForm] = useState(false);
  const [ingSuggestion, setIngSuggestion] = useState({ name: '', ingredientType: 'quantity' });
  const [suggestingIng, setSuggestingIng] = useState(false);
  const [ingSuggestSuccess, setIngSuggestSuccess] = useState(false);

  const loadData = useCallback(async () => {
    const [drinksRes, ordersRes, ingRes, reviewsRes] = await Promise.all([
      axios.get(`${API_BASE}/drinks`, { headers: { Authorization: token } }),
      axios.get(`${API_BASE}/orders`, { headers: { Authorization: token } }),
      axios.get(`${API_BASE}/ingredients`, { headers: { Authorization: token } }),
      axios.get(`${API_BASE}/reviews`, { headers: { Authorization: token } }),
    ]);
    setDrinks(drinksRes.data.filter(d => d.available));
    setOrders(ordersRes.data);
    setIngredients(ingRes.data);
    setReviews(reviewsRes.data);
  }, [token]);

  useEffect(() => {
    loadData().finally(() => setLoading(false));
    const interval = setInterval(loadData, openChat ? 3000 : 15000);
    return () => clearInterval(interval);
  }, [loadData, openChat]);

  async function placeOrder(drink) {
    setSubmitting(true);
    try {
      const mods = Object.entries(modifications).map(([id, mod]) => {
        const ing = drink.ingredients.find(i => i.id === id) || ingredients.find(i => i.id === id);
        return { id, name: ing ? ing.name : id, type: ing ? ing.type : 'quantity', ...mod };
      });
      const res = await axios.post(`${API_BASE}/orders`, {
        drinkId: drink.id, drinkName: drink.name, notes, ice, glass, modifications: mods,
      }, { headers: { Authorization: token } });
      setOrders(prev => [res.data, ...prev]);
      setOrdering(null); setNotes(''); setIce(0); setGlass('clear');
      setModifications({}); setExpandedMod(null);
      setSuccess(drink.name);
      setTimeout(() => setSuccess(null), 3000);
    } catch (e) {} finally { setSubmitting(false); }
  }

  async function sendMessage(order) {
    const text = chatInput[order.id]?.trim();
    if (!text) return;
    setSendingMsg(true);
    try {
      const res = await axios.post(`${API_BASE}/orders/${order.id}/message`, { text }, { headers: { Authorization: token } });
      setOrders(prev => prev.map(o => o.id === order.id
        ? { ...o, messages: [...(o.messages || []), res.data] } : o));
      setChatInput(prev => ({ ...prev, [order.id]: '' }));
    } catch (e) {} finally { setSendingMsg(false); }
  }

  function inStock(id) {
    const ing = ingredients.find(i => i.id === id);
    if (!ing) return true;
    if (ing.type === 'quantity') return (ing.quantity || 0) > 0;
    return ing.inStock !== false;
  }

  const activeOrders = orders.filter(o => o.status !== 'delivered');

  if (loading) return <div className="loading"><div className="spinner" />Loading...</div>;

  return (
    <div className="user-view">
      <div className="tab-bar">
        <button className={tab === 'main' ? 'tab active' : 'tab'} onClick={() => setTab('main')}>Orders</button>
        <button className={tab === 'reviews' ? 'tab active' : 'tab'} onClick={() => setTab('reviews')}>Reviews</button>
      </div>

      {tab === 'reviews' && (
        <div className="reviews-tab">
          <div className="review-form">
            <h2>Leave a Review</h2>
            {reviewSuccess
              ? <div className="review-success">Thanks for your review! ⭐</div>
              : <>
                  <StarPicker value={reviewRating} onChange={setReviewRating} />
                  <textarea className="review-message-input" placeholder="Tell us more (optional)..."
                    value={reviewMessage} onChange={e => setReviewMessage(e.target.value)} rows={3} maxLength={500} />
                  <button className="confirm-btn" disabled={!reviewRating || submittingReview} onClick={async () => {
                    setSubmittingReview(true);
                    try {
                      const res = await axios.post(`${API_BASE}/reviews`, { rating: reviewRating, message: reviewMessage },
                        { headers: { Authorization: token } });
                      setReviews(prev => [res.data, ...prev]);
                      setReviewRating(null); setReviewMessage('');
                      setReviewSuccess(true);
                      setTimeout(() => setReviewSuccess(false), 4000);
                    } catch(e) {} finally { setSubmittingReview(false); }
                  }}>
                    {submittingReview ? 'Submitting...' : 'Submit Review'}
                  </button>
                </>
            }
          </div>
          <div className="reviews-list">
            <h2>All Reviews</h2>
            {reviews.length === 0
              ? <div className="empty">No reviews yet — be the first!</div>
              : reviews.map(r => (
                <div key={r.id} className="review-card">
                  <div className="review-top">
                    <StarDisplay rating={r.rating} />
                    <span className="review-user">{r.userName}</span>
                    <span className="review-date">{new Date(r.createdAt + 'Z').toLocaleDateString()}</span>
                  </div>
                  {r.message && <p className="review-msg">{r.message}</p>}
                </div>
              ))
            }
          </div>
        </div>
      )}

      {tab === 'main' && <>
        {success && <div className="success-toast">🍹 {success} ordered!</div>}
        {suggestSuccess && <div className="success-toast">💡 Drink suggestion sent!</div>}
        {ingSuggestSuccess && <div className="success-toast">🧪 Ingredient suggestion sent!</div>}

        {activeOrders.length > 0 && (
          <section className="active-orders">
            <h2>Your Orders</h2>
            {activeOrders.map(order => (
              <div key={order.id} className={`order-status-card ${order.status}`}>
                <div className="order-status-top">
                  <span className="status-icon">{STATUS_ICONS[order.status]}</span>
                  <div>
                    <div className="order-drink-name">{order.drinkName}</div>
                    <div className="order-status-label">{STATUS_LABELS[order.status]}</div>
                  </div>
                  {(order.status === 'making' || order.status === 'ready') && (
                    <button className="chat-toggle user" onClick={() => setOpenChat(openChat === order.id ? null : order.id)}>
                      💬{(order.messages||[]).length > 0 ? ` ${order.messages.length}` : ''}
                    </button>
                  )}
                </div>
                {(order.status === 'making' || order.status === 'ready') && openChat === order.id && (
                  <div className="chat-panel">
                    <div className="chat-messages">
                      {(order.messages || []).length === 0
                        ? <div className="chat-empty">No messages yet — ask Asher anything!</div>
                        : (order.messages || []).map(m => (
                          <div key={m.id} className={`chat-bubble ${m.isAdmin ? 'admin' : 'user'}`}>
                            <div className="chat-text">{m.text}</div>
                            <div className="chat-meta">{m.senderName}</div>
                          </div>
                        ))
                      }
                    </div>
                    <div className="chat-input-row">
                      <input className="chat-input" placeholder="Message Asher..."
                        value={chatInput[order.id] || ''}
                        onChange={e => setChatInput(p => ({ ...p, [order.id]: e.target.value }))}
                        onKeyDown={e => e.key === 'Enter' && sendMessage(order)} />
                      <button className="chat-send-btn" onClick={() => sendMessage(order)} disabled={sendingMsg}>Send</button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </section>
        )}

        <section className="drinks-menu">
          <h2>Menu</h2>
          <div className="drinks-list" style={{ maxHeight: '60vh', overflowY: 'auto' }}>
            {drinks.map(drink => {
              const isOrdering = ordering?.id === drink.id;
              const availableDrinkIngs = (drink.ingredients || []).filter(i => inStock(i.id));
              const addableIngredients = ingredients.filter(i => inStock(i.id) && !(drink.ingredients || []).find(d => d.id === i.id));

              return (
                <div key={drink.id} className="menu-card">
                  <div className="menu-card-info">
                    <div className="menu-drink-name" onClick={() => setExpandedDrink(expandedDrink === drink.id ? null : drink.id)} style={{ cursor: 'pointer' }}>
                      {drink.name} {expandedDrink === drink.id ? '▲' : '▼'}
                    </div>
                    {drink.description && <div className="menu-drink-desc">{drink.description}</div>}
                    {expandedDrink === drink.id && (drink.ingredients || []).length > 0 && (
                      <div className="recipe-section">
                        <div className="recipe-title">Ingredients</div>
                        <ul className="recipe-list">
                          {(drink.ingredients || []).map(ing => (
                            <li key={ing.id}>
                              {ing.name}
                              {ing.type === 'boolean'
                                ? ing.amount && <span className="recipe-qty"> {ing.amount}</span>
                                : <span className="recipe-qty"> ×{ing.quantity}</span>}
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </div>

                  {isOrdering ? (
                    <div className="order-form">
                      {/* Modifications */}
                      {(availableDrinkIngs.length > 0 || addableIngredients.length > 0) && (
                        <div className="mods-section">
                          <div className="mods-title">Customize</div>
                          {availableDrinkIngs.map(ing => {
                            const mod = modifications[ing.id];
                            return (
                              <div key={ing.id} className="mod-row">
                                <span className="mod-name">{ing.name}</span>
                                {mod ? (
                                  <div className="mod-controls">
                                    {mod.action === 'remove'
                                      ? <span className="mod-chip removed">✕ Removed</span>
                                      : <>
                                          {ing.type === 'boolean' ? (
                                            <div className="mod-actions">
                                              <button onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'modify', amount: Math.max(100, (mod.amount ?? ing.amount ?? 100) - 100) } }))}>−</button>
                                              <span>{mod.amount ?? ing.amount ?? 100}</span>
                                              <button onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'modify', amount: Math.min(800, (mod.amount ?? ing.amount ?? 100) + 100) } }))}>+</button>
                                            </div>
                                          ) : (
                                            <div className="mod-actions">
                                              <button onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'modify', quantity: Math.max(0.5, +((mod.quantity || ing.quantity) - 0.5).toFixed(1)) } }))}>−</button>
                                              <span>{mod.quantity ?? ing.quantity}</span>
                                              <button onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'modify', quantity: +((mod.quantity || ing.quantity) + 0.5).toFixed(1) } }))}>+</button>
                                            </div>
                                          )}
                                          <span className={`mod-chip ${mod.action}`}>{mod.action === 'modify' ? 'Modified' : 'Added'}</span>
                                        </>
                                    }
                                    <button className="mod-reset-btn" onClick={() => setModifications(p => { const n = { ...p }; delete n[ing.id]; return n; })}>↩</button>
                                  </div>
                                ) : (
                                  <div className="mod-actions">
                                    <button className="mod-undo-btn" onClick={() => setModifications(p => ({
                                      ...p,
                                      [ing.id]: ing.type === 'boolean'
                                        ? { action: 'modify', amount: ing.amount ?? 100 }
                                        : { action: 'modify', quantity: ing.quantity }
                                    }))}>Adjust</button>
                                    <button className="mod-remove-btn" onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'remove' } }))}>Remove</button>
                                  </div>
                                )}
                              </div>
                            );
                          })}
                          {addableIngredients.length > 0 && (
                            <div className="mod-add-section">
                              <div className="mods-title">Add ingredient</div>
                              <div className="picker-chips">
                                {addableIngredients.map(ing => {
                                  const mod = modifications[ing.id];
                                  return mod ? (
                                    <span key={ing.id} className="mod-chip added">
                                      + {ing.name}
                                      {ing.type !== 'boolean' && <span> ×{mod.quantity}</span>}
                                      <button onClick={() => setModifications(p => { const n = { ...p }; delete n[ing.id]; return n; })}>✕</button>
                                    </span>
                                  ) : (
                                    <button key={ing.id} className="picker-chip" onClick={() => setModifications(p => ({ ...p, [ing.id]: { action: 'add', quantity: 1 } }))}>
                                      + {ing.name}
                                    </button>
                                  );
                                })}
                              </div>
                            </div>
                          )}
                        </div>
                      )}

                      <div className="order-options">
                        <div className="option-group">
                          <label>Glass</label>
                          <div className="option-btns">
                            <button className={glass === 'clear' ? 'opt-btn active' : 'opt-btn'} onClick={() => setGlass('clear')}>🥃 Clear</button>
                            <button className={glass === 'green' ? 'opt-btn active' : 'opt-btn'} onClick={() => setGlass('green')}>🍵 Green</button>
                          </div>
                        </div>
                        <div className="option-group">
                          <label>Ice</label>
                          <div className="ice-controls">
                            <button onClick={() => setIce(Math.max(0, ice - 100))}>−</button>
                            <span>{ice === 0 ? 'None' : ice}</span>
                            <button onClick={() => setIce(Math.min(800, ice + 100))}>+</button>
                          </div>
                        </div>
                      </div>
                      <textarea className="notes-input" placeholder="Any notes for Asher?"
                        value={notes} onChange={e => setNotes(e.target.value)} rows={2} />
                      <div className="order-form-actions">
                        <button className="confirm-btn" onClick={() => placeOrder(drink)} disabled={submitting}>
                          {submitting ? 'Ordering...' : 'Confirm Order'}
                        </button>
                        <button className="cancel-btn" onClick={() => { setOrdering(null); setNotes(''); setIce(0); setGlass('clear'); setModifications({}); setExpandedMod(null); }}>Cancel</button>
                      </div>
                    </div>
                  ) : (
                    <button className="order-btn" onClick={() => setOrdering(drink)}>Order</button>
                  )}
                </div>
              );
            })}
          </div>
        </section>

        <section className="suggest-section">
          <div className="suggest-buttons">
            <button className="suggest-btn" onClick={() => { setShowSuggestForm(!showSuggestForm); setShowIngSuggestForm(false); }}>
              💡 Suggest a Drink
            </button>
            <button className="suggest-btn" onClick={() => { setShowIngSuggestForm(!showIngSuggestForm); setShowSuggestForm(false); }}>
              🧪 Suggest an Ingredient
            </button>
          </div>

          {showSuggestForm && (
            <div className="suggest-form">
              <h3>Suggest a Drink</h3>
              <input placeholder="Drink name" value={suggestion.name}
                onChange={e => setSuggestion(p => ({ ...p, name: e.target.value }))} />
              <textarea placeholder="Description (optional)" value={suggestion.description}
                onChange={e => setSuggestion(p => ({ ...p, description: e.target.value }))} rows={2} />
              <IngredientPicker
                available={ingredients}
                selected={suggestion.ingredients}
                onChange={ings => setSuggestion(p => ({ ...p, ingredients: ings }))}
              />
              <div className="order-form-actions">
                <button className="confirm-btn" disabled={!suggestion.name.trim() || suggesting} onClick={async () => {
                  setSuggesting(true);
                  try {
                    await axios.post(`${API_BASE}/suggestions`, { suggestionType: 'drink', ...suggestion }, { headers: { Authorization: token } });
                    setSuggestion({ name: '', description: '', ingredients: [] });
                    setShowSuggestForm(false);
                    setSuggestSuccess(true);
                    setTimeout(() => setSuggestSuccess(false), 3000);
                  } catch(e) {} finally { setSuggesting(false); }
                }}>
                  {suggesting ? 'Sending...' : 'Submit Suggestion'}
                </button>
                <button className="cancel-btn" onClick={() => setShowSuggestForm(false)}>Cancel</button>
              </div>
            </div>
          )}

          {showIngSuggestForm && (
            <div className="suggest-form">
              <h3>Suggest an Ingredient</h3>
              <input placeholder="Ingredient name" value={ingSuggestion.name}
                onChange={e => setIngSuggestion(p => ({ ...p, name: e.target.value }))} />
              <div className="option-group">
                <label>Type</label>
                <div className="option-btns">
                  <button className={ingSuggestion.ingredientType === 'quantity' ? 'opt-btn active' : 'opt-btn'}
                    onClick={() => setIngSuggestion(p => ({ ...p, ingredientType: 'quantity' }))}>Quantity</button>
                  <button className={ingSuggestion.ingredientType === 'boolean' ? 'opt-btn active' : 'opt-btn'}
                    onClick={() => setIngSuggestion(p => ({ ...p, ingredientType: 'boolean' }))}>In/Out of Stock</button>
                  <button className={ingSuggestion.ingredientType === 'squirt' ? 'opt-btn active' : 'opt-btn'}
                    onClick={() => setIngSuggestion(p => ({ ...p, ingredientType: 'squirt' }))}>Squirt</button>
                </div>
              </div>
              <div className="order-form-actions">
                <button className="confirm-btn" disabled={!ingSuggestion.name.trim() || suggestingIng} onClick={async () => {
                  setSuggestingIng(true);
                  try {
                    await axios.post(`${API_BASE}/suggestions`, { suggestionType: 'ingredient', ...ingSuggestion }, { headers: { Authorization: token } });
                    setIngSuggestion({ name: '', ingredientType: 'quantity' });
                    setShowIngSuggestForm(false);
                    setIngSuggestSuccess(true);
                    setTimeout(() => setIngSuggestSuccess(false), 3000);
                  } catch(e) {} finally { setSuggestingIng(false); }
                }}>
                  {suggestingIng ? 'Sending...' : 'Submit Suggestion'}
                </button>
                <button className="cancel-btn" onClick={() => setShowIngSuggestForm(false)}>Cancel</button>
              </div>
            </div>
          )}
        </section>
      </>}
    </div>
  );
}
